                          <div style="font-size:12px; font-weight:900;">${v.text || '---'}</div>
                          <div style="display:grid; grid-template-columns: repeat(3, 1fr); gap:5px; margin-top:5px;">
                            ${v.attachments.filter(a => a.type === 'image').map(a => `<img src="${a.url}" style="width:100%; border-radius:3px; border:1px solid #ddd;"/>`).join('')}
                          </div>
