                                                  value={sv.consumption_val}
                                                  onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                  onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_type; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                />
                                              </div>

                                              <textarea 
                                                className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[60px]"
                                                placeholder="Instructions for selected size pool..."
                                                value={sv.text}
                                                onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />

                                              <div className="flex flex-wrap gap-2">
                                                {sv.attachments.map((a, aIdx) => (
                                                  <div key={aIdx} className="flex items-center gap-1 bg-white border border-blue-50 px-2 py-1 rounded text-[9px] font-black text-blue-700">{a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button></div>
                                                ))}
                                                <label className="bg-white border-2 border-dashed border-blue-100 text-blue-300 px-3 py-1 rounded-lg text-[9px] font-black cursor-pointer hover:bg-blue-50 transition-all">+ File <input type="file" multiple className="hidden" onChange={async (e) => {
                                                  if (!e.target.files) return;
                                                  setIsUploading(true);
                                                  const newAtts = [];
                                                  const files = Array.from(e.target.files) as File[];
                                                  for (const file of files) {
                                                    const url = await uploadOrderAttachment(file);
                                                    if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                  }
                                                  const updated = { ...fieldData };
                                                  updated.variants![vIdx].sizeVariants![svIdx].attachments = [...(updated.variants![vIdx].sizeVariants![svIdx].attachments || []), ...newAtts];
                                                  setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                  setIsUploading(false);
                                                }}/></label>
                                              </div>
                                            </div>
                                          ))}
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50">+ Add Size Sub-Split</button>
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                  <button type="button" onClick={() => handleSplitColor(fieldKey)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 transition-all">+ Add Bulk Color Group Variant</button>
                                </div>
                              )}
                           </div>
                         )}
                      </div>
                    );
                  })}
                </div>
             </div>
           ))}
        </div>

        <div className="p-8 border-t bg-white flex justify-between items-center shadow-2xl shrink-0">
          <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
          <button 
            onClick={handleEnhancedExecute} 
            disabled={isUploading}
            className="px-12 py-4 bg-orange-600 text-white rounded-2xl font-black shadow-2xl shadow-orange-200 flex items-center gap-3 active:scale-95 disabled:opacity-50 uppercase text-xs"
          >
            {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Save size={20}/>} Sync Selected Blueprint Fields
          </button>
        </div>
      </div>
    </div>
  );
};

import { Order, Style, ConsumptionType, Attachment, SizeBreakdown } from '../types';

export interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

export interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
  if (!val) return 0;
  return type === 'items_per_pc' ? qty * val : qty / val;
};

export const getDetailedRequirements = (order: Order, style: Style): DetailedRequirement[] => {
  if (!style || !order.size_breakdown) return [];

  const detailedReqs: DetailedRequirement[] = [];
  const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
  const isNumeric = order.size_format === 'numeric';
  const sizeLabels = isNumeric ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const getRowTotal = (row: SizeBreakdown) => 
    (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);

  for (const catName in style.tech_pack) {
    for (const fieldName in style.tech_pack[catName]) {
      const item = style.tech_pack[catName][fieldName];
      const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

      if (item.variants) {
        for (const variant of item.variants) {
          const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
          if (matchingRows.length === 0) continue;

          if (variant.sizeVariants) {
            for (const sv of variant.sizeVariants) {
              const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
              const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

              if (qty > 0) {
                const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                const calc = calculateRequirementValue(qty, rType, rVal);

                req.breakdown.push({
                  label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                  count: qty,
                  calc: Math.ceil(calc * 100) / 100,
                  text: sv.text || variant.text || item.text,
                  attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                });
                req.total += calc;
              }
            }
          } else if (variant.consumption_type) {
            const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
            const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
            req.breakdown.push({
              label: `Color: ${variant.colors.join('/')}`,
              count: qty,
              calc: Math.ceil(calc * 100) / 100,
              text: variant.text || item.text,
              attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
            });
            req.total += calc;
          }
        }
      } else if (item.consumption_type) {
        const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
        req.breakdown.push({
          label: "Global (All Colors/Sizes)",
          count: order.quantity,
          calc: Math.ceil(calc * 100) / 100,
          text: item.text,
          attachments: item.attachments
        });
        req.total = calc;
      }

      if (req.total > 0) {
        req.total = Math.ceil(req.total * 100) / 100;
        detailedReqs.push(req);
      }
    }
  }
  return detailedReqs;
};

import React, { useState, useEffect } from 'react';
import { Order, MaterialRequest, Style, Attachment } from '../../types';
import { X, Trash2, Calculator, ArrowLeftRight, Check, Plus, Paperclip, Files, Loader2, Zap, Info, ImageIcon, FileText, AlertCircle, RefreshCcw } from 'lucide-react';
import { uploadOrderAttachment, createMaterialRequest, updateMaterialRequest, fetchStyleByNumber, fetchMaterialRequests } from '../../services/db';
import { getDetailedRequirements, DetailedRequirement } from '../../services/forecast';

interface MaterialRow {
  id: number;
  name: string;
  qtyPerPc: number;
  targetPcs: number;
  targetLabel: string;
  requestQty: number;
  unit: string;
  files: File[];
}

interface ForecastedItem {
  id: string;
  name: string;
  label: string;
  requiredTotal: number;
  alreadyRequested: number;
  balanceToSync: number;
  unit: string;
  text: string;
  attachments: Attachment[];
  isSelected: boolean;
}

interface MaterialRequestModalProps {
  orderId: string;
  orderNo: string;
  orders: Order[];
  onClose: () => void;
  isEditingRequest: { id: string; originalData: MaterialRequest } | null;
  useNumericSizes: boolean;
  onRefresh: () => void;
}

export const MaterialRequestModal: React.FC<MaterialRequestModalProps> = ({
  orderId,
  orderNo,
  orders,
  onClose,
  isEditingRequest,
  useNumericSizes,
  onRefresh
}) => {
  const order = orders.find(o => o.id === orderId);
  const initialQty = order ? order.quantity : 0;

  const [reqTab, setReqTab] = useState<'direct' | 'pcs' | 'forecast'>(isEditingRequest ? 'direct' : 'forecast');
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [isStyleLoading, setIsStyleLoading] = useState(false);
  const [existingRequests, setExistingRequests] = useState<MaterialRequest[]>([]);

  const [materialRows, setMaterialRows] = useState<MaterialRow[]>(
    isEditingRequest 
      ? [{ id: 1, name: isEditingRequest.originalData.material_content, qtyPerPc: 0, targetPcs: 0, targetLabel: '', requestQty: isEditingRequest.originalData.quantity_requested, unit: isEditingRequest.originalData.unit, files: [] }]
      : [{ id: 1, name: '', qtyPerPc: 0, targetPcs: initialQty, targetLabel: `Full Order (${initialQty})`, requestQty: 0, unit: 'Nos', files: [] }]
  );

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [qtyFilterModal, setQtyFilterModal] = useState<{ isOpen: boolean, rowIndex: number | null }>({ isOpen: false, rowIndex: null });
  const [filterMode, setFilterMode] = useState<'matrix' | 'manual'>('matrix');
  const [selectedRows, setSelectedRows] = useState<number[]>([]);
  const [selectedCols, setSelectedCols] = useState<string[]>([]);
  const [manualOverrideQty, setManualOverrideQty] = useState<number>(0);
  const [forecastItems, setForecastItems] = useState<ForecastedItem[]>([]);

  // Fetch Style, Forecasts and existing requests
  useEffect(() => {
    const loadTechnicalContext = async () => {
      if (!order) return;
      setIsStyleLoading(true);

      const styleRefPart = order.style_number.split(' - ')[0].trim();
      const [style, reqs] = await Promise.all([
        fetchStyleByNumber(styleRefPart),
        fetchMaterialRequests()
      ]);

      const orderReqs = reqs.filter(r => r.order_id === orderId);
      setLinkedStyle(style);
      setExistingRequests(orderReqs);

      if (style) {
        const blueprintReqs = getDetailedRequirements(order, style);
        const items: ForecastedItem[] = [];

        blueprintReqs.forEach(req => {
          req.breakdown.forEach(b => {
            const materialId = `${req.name} (${b.label})`;

            // Check if we've already requested this item
            // We match by content string as that's how it's stored
            const alreadyRequestedSum = orderReqs
              .filter(r => r.material_content === materialId)
              .reduce((sum, r) => sum + r.quantity_requested, 0);

            const balance = Math.max(0, b.calc - alreadyRequestedSum);

            items.push({
              id: `${req.name}-${b.label}`,
              name: req.name,
              label: b.label,
              requiredTotal: b.calc,
              alreadyRequested: alreadyRequestedSum,
              balanceToSync: balance,
              unit: 'Nos',
              text: b.text,
              attachments: b.attachments,
              isSelected: balance > 0 // Auto-select items that have a positive balance
            });
          });
        });
        setForecastItems(items);
      }
      setIsStyleLoading(false);
    };

    loadTechnicalContext();
  }, [orderId, order]);

  const handleRowChange = (id: number, field: keyof MaterialRow, value: any) => {
    setMaterialRows(prev => prev.map(row => row.id === id ? { ...row, [field]: value } : row));
  };

  const addRow = () => {
    setMaterialRows(prev => [...prev, { id: Date.now(), name: '', qtyPerPc: 0, targetPcs: initialQty, targetLabel: `Full Order (${initialQty})`, requestQty: 0, unit: 'Nos', files: [] }]);
  };

  const removeRow = (id: number) => {
    setMaterialRows(prev => prev.filter(row => row.id !== id));
  };

  const calculateSelection = () => {
    if (!order || !order.size_breakdown) return 0;
    let total = 0;
    order.size_breakdown.forEach((row, rIdx) => {
      const sizeKeys: ('s' | 'm' | 'l' | 'xl' | 'xxl' | 'xxxl')[] = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'];
      sizeKeys.forEach(key => {
        if (selectedRows.includes(rIdx) || selectedCols.includes(key)) {
          total += (row[key] as number) || 0;
        }
      });
    });
    return total;
  };

  const handleConfirmQtyFilter = () => {
    if (qtyFilterModal.rowIndex === null) return;
    let finalQty = filterMode === 'manual' ? manualOverrideQty : calculateSelection();
    let label = filterMode === 'manual' ? `Manual (${finalQty})` : `Filter: ${selectedRows.length} Colors, ${selectedCols.length} Sizes`;
    const targetRowId = materialRows[qtyFilterModal.rowIndex].id;
    handleRowChange(targetRowId, 'targetPcs', finalQty);
    handleRowChange(targetRowId, 'targetLabel', label);
    setQtyFilterModal({ isOpen: false, rowIndex: null });
  };

  const toggleForecastSelection = (id: string) => {
    setForecastItems(prev => prev.map(item => item.id === id ? { ...item, isSelected: !item.isSelected } : item));
  };

  const handleSelectAllForecast = (select: boolean) => {
    setForecastItems(prev => prev.map(item => ({ ...item, isSelected: select })));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      if (reqTab === 'forecast') {
        const toSync = forecastItems.filter(i => i.isSelected);
        if (toSync.length === 0) {
          alert("No items selected for sync.");
          setIsSubmitting(false);
          return;
        }
        for (const item of toSync) {
          // Syncing the BALANCE, not the full requirement (to prevent double-ordering)
          if (item.balanceToSync <= 0) continue;
          await createMaterialRequest({ 
            order_id: orderId, 
            material_content: `${item.name} (${item.label})`, 
            quantity_requested: item.balanceToSync, 
            unit: item.unit, 
            attachments: item.attachments as any 
          });
        }
      } else {
        for (const row of materialRows) {
          if (!row.name) continue;
          let finalQty = reqTab === 'direct' ? row.requestQty : (row.qtyPerPc * row.targetPcs);
          if (finalQty <= 0) continue;
          const attachments = [];
          for (const file of row.files) {
            const url = await uploadOrderAttachment(file);
            if (url) attachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
          }
          if (isEditingRequest) {
            await updateMaterialRequest(isEditingRequest.id, { material_content: row.name, quantity_requested: finalQty, unit: row.unit, attachments: attachments.length > 0 ? attachments as any : undefined });
          } else {
            await createMaterialRequest({ order_id: orderId, material_content: row.name, quantity_requested: finalQty, unit: row.unit, attachments: attachments as any });
          }
        }
      }
      onRefresh();
      onClose();
    } catch (err) {
      alert("Submission error. Check logs.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const matrixHeaders = useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const matrixKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'];

  return (
    <div className="fixed inset-0 bg-black/70 bg-opacity-50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col max-h-[90vh] animate-scale-up">
        <div className="p-6 border-b flex justify-between items-center bg-gradient-to-r from-blue-600 to-indigo-700 text-white">
          <div>
            <h3 className="text-2xl font-black flex items-center gap-2">
              <Calculator size={28}/> Accessories Requisition
            </h3>
            <p className="text-blue-100 text-sm font-bold opacity-80 mt-1 uppercase tracking-widest">Order: {orderNo}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={28} /></button>
        </div>

        <div className="p-8 space-y-6 overflow-y-auto flex-1 bg-slate-50/50">
          <div className="flex bg-slate-200 p-1.5 rounded-xl w-fit shadow-inner">
            <button 
              onClick={() => setReqTab('forecast')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'forecast' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Zap size={16}/> Dynamic Forecast Sync
            </button>
            <button 
              onClick={() => setReqTab('pcs')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'pcs' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Calculator size={16}/> Calculator Mode
            </button>
            <button 
              onClick={() => setReqTab('direct')} 
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-black transition-all ${reqTab === 'direct' ? 'bg-white text-indigo-600 shadow-lg scale-105' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <Files size={16}/> Direct Entry
            </button>
          </div>

          {reqTab === 'forecast' ? (
            <div className="space-y-4 animate-fade-in">
              <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-4 flex items-center gap-3">
                 <Info className="text-indigo-500" size={20}/>
                 <div>
                   <p className="text-xs font-bold text-indigo-800">Requirements are calculated live from the Style DB.</p>
                   <p className="text-[10px] text-indigo-400 font-bold uppercase mt-0.5">If the blueprint was updated after order creation, the delta will show in "Balance to Sync".</p>
                 </div>
              </div>

              {isStyleLoading ? (
                <div className="py-20 text-center flex flex-col items-center">
                   <Loader2 size={40} className="animate-spin text-indigo-600 mb-4"/>
                   <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Processing Blueprint Delta...</p>
                </div>
              ) : !linkedStyle ? (
