                    </a>
                    {isEditing && (
                      <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500 transition-colors">
                        <Trash2 size={20}/>
                      </button>
