            <div class="section-title">Color / Size Breakdown Matrix</div>
            <table>
              <thead>
                <tr><th style="text-align:left; border: 1px solid #333; font-weight:900 !important;">Color Variant</th>${headers.map(h => `<th style="border: 1px solid #333; font-weight:900 !important;">${h}</th>`).join('')}<th style="border: 1px solid #333; font-weight:900 !important;">Total</th></tr>
