      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
          onPrintMaterials={() => handlePrintMaterialForecast(detailsModal)}
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, fetchUnits, fetchBarcodes, triggerOrderEmail, fetchOrderLogs, fetchStyles, fetchMaterialRequests, createMaterialRequest } from '../services/db';
import { Order, Unit, OrderStatus, BarcodeStatus, formatOrderNumber, OrderLog, Style } from '../types';
import { BarChart3, PieChart, PlusCircle, ClipboardList, Printer, Loader2, RefreshCcw, Zap, AlertCircle, CheckCircle2 } from 'lucide-react';
import { DashboardStats } from '../components/admin/DashboardStats';
import { MasterOrderList } from '../components/admin/MasterOrderList';
import { LaunchOrderModal } from '../components/admin/LaunchOrderModal';
import { AdminOrderDetailsModal } from '../components/admin/AdminOrderDetailsModal';
import { getDetailedRequirements } from '../services/forecast';

export const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'reports'>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
  const [liveStockCount, setLiveStockCount] = useState(0);
  const [activeOrderCount, setActiveOrderCount] = useState(0);
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [isLaunchModalOpen, setIsLaunchModalOpen] = useState(false);
  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [reportLoading, setReportLoading] = useState(false);
  const [syncLoading, setSyncLoading] = useState(false);

  const loadData = async () => {
    const [fetchedOrders, fetchedUnits, fetchedStock] = await Promise.all([
        fetchOrders(), 
        fetchUnits(),
        fetchBarcodes(BarcodeStatus.COMMITTED_TO_STOCK)
    ]);
    setOrders(fetchedOrders);
    setUnits(fetchedUnits);
    setLiveStockCount(fetchedStock.length);
    setActiveOrderCount(fetchedOrders.filter(o => o.status !== OrderStatus.COMPLETED).length);
  };

  useEffect(() => { loadData(); }, [activeTab]);

  const handleGlobalForecastSync = async () => {
    if (!confirm("This will analyze all running orders against the latest Style DB blueprints and push any missing material requirements to the warehouse. Proceed?")) return;

    setSyncLoading(true);
    try {
      const activeOrders = orders.filter(o => o.status !== OrderStatus.COMPLETED);
      const allStyles = await fetchStyles();
      const allRequests = await fetchMaterialRequests();

      let syncCount = 0;
      let newReqItems = 0;

      for (const order of activeOrders) {
        const styleRefPart = order.style_number.split(' - ')[0].trim();
        const linkedStyle = allStyles.find(s => s.style_number === styleRefPart);

        if (!linkedStyle) continue;

        const liveForecast = getDetailedRequirements(order, linkedStyle);
        const orderExistingReqs = allRequests.filter(r => r.order_id === order.id);

        let orderHadUpdates = false;

        for (const reqCategory of liveForecast) {
          for (const breakdownItem of reqCategory.breakdown) {
            const materialIdentity = `${reqCategory.name} (${breakdownItem.label})`;

            // Calculate what's already been requested for this specific line item
            const alreadyRequestedSum = orderExistingReqs
              .filter(r => r.material_content === materialIdentity)
              .reduce((sum, r) => sum + r.quantity_requested, 0);

            const delta = Math.max(0, breakdownItem.calc - alreadyRequestedSum);

            if (delta > 0.01) { // Threshold for floating point
              await createMaterialRequest({
                order_id: order.id,
                material_content: materialIdentity,
                quantity_requested: delta,
                unit: 'Nos',
                attachments: breakdownItem.attachments as any
              });
              newReqItems++;
              orderHadUpdates = true;
            }
          }
        }

        if (orderHadUpdates) syncCount++;
      }

      alert(`Sync Complete!\n\nOrders Updated: ${syncCount}\nNew Material Requests Generated: ${newReqItems}`);
      loadData();
    } catch (err: any) {
      alert("Error during global sync: " + err.message);
    } finally {
      setSyncLoading(false);
    }
  };

  const handleSendEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerOrderEmail(orderId, false);
    setEmailLoading(null);
    alert(result.message);
  };

  const handlePrintUnitReport = async () => {
    setReportLoading(true);
    try {
      const inProgressOrders = orders.filter(o => o.status === OrderStatus.IN_PROGRESS);
      const assignedOrders = orders.filter(o => o.status === OrderStatus.ASSIGNED);

      const allLogs = await fetchOrderLogs();
      const inProgressOrderIds = inProgressOrders.map(o => o.id);

      // Filter logs for in-progress orders, sort by date descending, and take the last 5
      const recentLogs = allLogs
        .filter(log => inProgressOrderIds.includes(log.order_id))
        .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 5);

      // Group these top 5 logs by order_id
      const groupedLogs: Record<string, OrderLog[]> = {};
      recentLogs.forEach(log => {
        if (!groupedLogs[log.order_id]) groupedLogs[log.order_id] = [];
        groupedLogs[log.order_id].push(log);
      });

      const win = window.open('', 'UnitReport', 'width=1000,height=800');
      if (win) {
        const logSectionsHtml = Object.entries(groupedLogs).map(([orderId, logs]) => {
          const order = inProgressOrders.find(o => o.id === orderId);
          const orderRef = order ? formatOrderNumber(order) : 'UNK';

          return `
            <div style="margin-bottom: 20px; border: 1.5px solid #1e293b; border-radius: 8px; overflow: hidden; page-break-inside: avoid;">
              <div style="background: #1e293b; padding: 10px 15px; font-weight: 900; color: #fff; font-size: 13px; text-transform: uppercase;">
                Job Ref: ${orderRef}
              </div>
              <table style="width: 100%; border-collapse: collapse; background: #fff;">
                <tbody style="font-size: 11px;">
                  ${logs.map(log => `
                    <tr style="border-bottom: 1px solid #e2e8f0;">
                      <td style="padding: 10px; width: 160px; color: #64748b; font-weight: bold; border-right: 1px solid #e2e8f0;">${new Date(log.created_at).toLocaleString()}</td>
                      <td style="padding: 10px; color: #1e293b; font-weight: 500;">${log.message}</td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `;
        }).join('');

        const assignedRows = assignedOrders.map(order => `
          <tr>
            <td style="padding: 10px; border: 1px solid #ddd; font-weight: bold;">${formatOrderNumber(order)}</td>
            <td style="padding: 10px; border: 1px solid #ddd;">${order.style_number}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center; font-weight: bold;">${order.quantity}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center;">${order.target_delivery_date}</td>
          </tr>
        `).join('');

        win.document.write(`
          <html>
          <head>
            <title>Unit Production Report</title>
            <style>
              body { font-family: sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; background: #fff; }
              .header { border-bottom: 4px solid #000; padding-bottom: 20px; margin-bottom: 30px; text-align: center; }
              .brand { font-size: 28px; font-weight: 900; letter-spacing: 1px; }
              .title { font-size: 16px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-top: 5px; }
              .section-title { font-size: 14px; font-weight: 900; background: #f1f5f9; padding: 10px 15px; border-left: 6px solid #1e293b; margin: 40px 0 20px 0; text-transform: uppercase; letter-spacing: 1px; }
              table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; }
              th { background: #f8fafc; text-align: left; padding: 12px; border: 1px solid #ddd; text-transform: uppercase; font-size: 10px; color: #64748b; }
              .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #eee; padding-top: 20px; }
              @media print { body { padding: 20px; } .section-title { -webkit-print-color-adjust: exact; } }
            </style>
          </head>
          <body>
            <div class="header">
              <div class="brand">TINTURA SST</div>
              <div class="title">Manufacturing Unit Executive Report</div>
              <div style="font-size: 11px; margin-top: 10px; font-weight: bold; color: #94a3b8;">DISPATCHED: ${new Date().toLocaleString()}</div>
            </div>

            <div class="section-title">Recent Timeline Activity (Last 5 Global Updates)</div>
            ${recentLogs.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">No recent floor activity logs recorded for in-progress jobs.</p>' : logSectionsHtml}

            <div class="section-title">Queue Status (Assigned & Unstarted Jobs)</div>
            ${assignedOrders.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">Assigned queue is currently empty.</p>' : `
            <table>
              <thead>
                <tr>
                  <th width="150">Order Ref</th>
                  <th>Style Reference</th>
                  <th width="100" style="text-align: center;">Batch Vol</th>
                  <th width="120" style="text-align: center;">Target Date</th>
                </tr>
              </thead>
              <tbody>${assignedRows}</tbody>
            </table>
            `}

            <div class="footer">
              This report is generated automatically by Tintura SST HQ. 
              <br/>For internal manufacturing supervision only.
            </div>
            <script>window.onload = () => { setTimeout(() => { window.print(); }, 500); };</script>
          </body>
          </html>
        `);
        win.document.close();
      }
    } catch (err) {
      console.error(err);
      alert("Critical: Failed to compile unit report.");
    } finally {
      setReportLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">
          {activeTab === 'overview' ? 'Executive Dashboard' : 'Analytics & Reports'}
        </h2>
        <div className="flex items-center gap-2">
            <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('overview')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'overview' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><BarChart3 size={18}/> Overview</button>
                <button onClick={() => setActiveTab('reports')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><PieChart size={18}/> Reports</button>
            </div>
            {activeTab === 'overview' && (
                <div className="flex gap-2">
                  <button 
                    onClick={handleGlobalForecastSync} 
                    disabled={syncLoading}
                    className="bg-orange-50 border-2 border-orange-200 text-orange-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-orange-100 shadow-md transition-all active:scale-95 disabled:opacity-50"
                    title="Update material requirements for all active orders based on latest Style blueprints"
                  >
                    {syncLoading ? <Loader2 size={20} className="animate-spin" /> : <Zap size={20} />}
                    <span className="font-black text-xs uppercase tracking-widest">Global Forecast Sync</span>
                  </button>
                  <button 
                    onClick={handlePrintUnitReport} 
                    disabled={reportLoading}
                    className="bg-white border-2 border-indigo-600 text-indigo-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-50 shadow-md transition-all active:scale-95 disabled:opacity-50"
                  >
                    {reportLoading ? <Loader2 size={20} className="animate-spin" /> : <ClipboardList size={20} />}
                    <span>Unit Report</span>
                  </button>
                  <button onClick={() => setIsLaunchModalOpen(true)} className="bg-indigo-600 text-white px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95">
                    <PlusCircle size={20} /><span>Launch New Order</span>
                  </button>
                </div>
            )}
        </div>
      </div>

      {activeTab === 'overview' ? (
        <div className="space-y-6 animate-fade-in">
            <DashboardStats liveStockCount={liveStockCount} activeOrderCount={activeOrderCount} />
            <MasterOrderList 
              orders={orders} 
              units={units} 
              onRefresh={loadData} 
              onViewDetails={setDetailsModal} 
              onSendEmail={handleSendEmail} 
              emailLoading={emailLoading}
            />
        </div>
      ) : (
        <div className="bg-white p-20 rounded-2xl border border-slate-200 text-center text-slate-400 animate-fade-in">
           <PieChart size={48} className="mx-auto mb-4 opacity-20"/>
           <p className="text-lg font-bold">Reporting Suite</p>
           <p className="text-sm">Detailed production analytics and performance KPIs are currently being compiled.</p>
        </div>
      )}

      <LaunchOrderModal 
        isOpen={isLaunchModalOpen} 
        onClose={() => setIsLaunchModalOpen(false)} 
        units={units} 
        onSuccess={loadData} 
      />

      {detailsModal && (
        <AdminOrderDetailsModal 
          order={detailsModal} 
          units={units} 
          onClose={() => setDetailsModal(null)} 
          onRefresh={loadData} 
        />
      )}
    </div>
  );
};
